-- Enrichment marathon batch: Bolt, Bomi Player, Bonsai (Hello Bonsai), Bonsai (bonsai.io), Bookmark OS, Bookworm, Boomi, boomurl

-- ── Bolt ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Bolt is a US-based fintech company that provides one-click checkout and payment infrastructure for online merchants. It is unrelated to Bolt (formerly Taxify), the Estonia-based ride-hailing and mobility super-app at bolt.eu.$q$, short_description),
  pricing_model = COALESCE($q$custom$q$, pricing_model),
  starting_price = COALESCE(NULL, starting_price),
  founded_year = COALESCE(2014, founded_year),
  company_size = COALESCE($q$Roughly 300-500 employees (headcount has fluctuated with layoffs since 2022)$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, US$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Bolt (bolt.com) Review: One-Click Checkout Fintech$q$, seo_title),
  seo_meta_description = COALESCE($q$Bolt is a US fintech offering one-click checkout for online merchants. See what Bolt.com does, its funding history, and how it differs from ride-hailing app Bolt.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Bolt Financial Inc., operating at bolt.com, is an American financial technology company founded in 2014 in San Francisco by Stanford students Ryan Breslow and Eric Feldman. Its core product, Bolt Checkout, lets e-commerce merchants offer shoppers a one-click purchase experience by reusing stored payment and shipping details across a shared shopper network, with the stated goal of reducing cart abandonment and helping independent retailers compete with Amazon-style checkout speed. Bolt should not be confused with Bolt (formerly Taxify), the unrelated Estonia-based ride-hailing and micromobility super-app that operates at bolt.eu across Europe and Africa; that company has no connection to Bolt Financial. Bolt Financial has raised roughly 1.6 billion dollars in total funding. Its most notable round was a 355 million dollar Series E in January 2022 that valued the company at around 11 billion dollars, making it a decacorn. Six days after that round closed, founder Ryan Breslow posted a Twitter thread criticizing Sequoia Capital and Y Combinator, then stepped down as CEO to become executive chairman; COO Maju Kuruvilla took over as CEO. In mid-2023, reports surfaced that the SEC was investigating whether Breslow made misleading statements to investors during the Series E fundraise, and some Series E investors alleged the round valued the company on inflated projections. Bolt's valuation subsequently became a point of dispute: some investor marks reportedly cut the company's valuation by roughly 97 percent to around 300 million dollars by early 2024, while other 2024 financing activity, including a 220 million dollar debt round and a reported 450 million dollar raise later that year, was associated with valuations cited anywhere from 11 billion to 14 billion dollars depending on the source. In March 2025, Ryan Breslow returned as CEO, and the company has since been reported on for aggressive internal restructuring, including cutting its HR department. Bolt remains headquartered in San Francisco and continues to sell checkout, fraud-prevention, and payments infrastructure to online merchants on a custom, enterprise-priced basis rather than published self-serve pricing.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '44eef01c-f79a-4511-9e31-f502a7e87cd8';

