-- ── Bomi Player ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Bomi, formerly known as CMPlayer, is a free and open-source graphical media player built on the mpv playback engine, historically available for Linux and, in earlier versions, macOS.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2008, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$, $q$Korean$q$, $q$Japanese$q$]::text[],
  seo_title = COALESCE($q$Bomi Player: Free Open-Source mpv Media Player$q$, seo_title),
  seo_meta_description = COALESCE($q$Bomi is a free, open-source GUI media player built on mpv. Explore its playback history, subtitle support, hardware decoding, and platform availability.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Bomi is a free and open-source graphical multimedia player built on top of the mpv playback engine, originally released under the name CMPlayer around 2008 by South Korean developer Lee Byoung-young, known online as xylosper, before being renamed to Bomi around 2014 to 2015. It is licensed under the GNU General Public License version 2, with source code hosted on GitHub, and its project page lives at bomi-player.github.io. Bomi wraps mpv's playback engine in a full graphical interface aimed at users who want mpv's power without relying purely on the command line. Notable capabilities include automatic playback history tracking with the ability to resume any file from where playback stopped, automatic playlist generation and restoration of the last-viewed list, and advanced subtitle handling that supports multiple simultaneous subtitle tracks in a wide range of formats, including styled formats like SAMI and ASS. Bomi also supports GPU-accelerated video decoding through VA-API and VDPAU on Linux, extensive customization of its interface, keyboard and mouse gesture controls, and a multilingual interface available in English, Korean, and Japanese, reflecting its Korean origins. Bomi's primary and best-supported platform is Linux; the software did have experimental macOS (then OS X) support in earlier releases, but that support was disabled after roughly version 0.8.17 when the developer's own Mac hardware broke, and macOS builds have not been an officially maintained part of the project since. There is no confirmed evidence of an actively maintained native Windows build being central to the project either, based on available project documentation. Development activity appears to have slowed significantly in the years since the project's most active period, though the software remains downloadable and usable for existing installations. Because it is completely free and open source with no paid tiers, subscriptions, or licensing fees, Bomi is best understood as a community-maintained alternative to players like VLC or a bare mpv installation, aimed at Linux users who want mpv's playback quality wrapped in a more approachable, configurable graphical shell.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'c8271070-c366-4c01-8ea4-620c98e6c346';

