-- ── Bonsai (bonsai.io) ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Bonsai, at bonsai.io, is a fully managed Elasticsearch and OpenSearch hosting platform for developers. Despite the similar name, it is a completely different, unrelated product from Hello Bonsai, the freelancer business-management tool covered separately in this directory.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free Sandbox tier; paid plans from around $15-25/month$q$, starting_price),
  founded_year = COALESCE(2009, founded_year),
  company_size = COALESCE($q$Small, bootstrapped and self-funded team$q$, company_size),
  headquarters = COALESCE($q$Austin, Texas, US$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Bonsai (bonsai.io) Review: Managed Elasticsearch Hosting$q$, seo_title),
  seo_meta_description = COALESCE($q$Bonsai.io offers fully managed Elasticsearch and OpenSearch hosting. See pricing, features, and how it differs from the unrelated freelancer tool Hello Bonsai.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Bonsai, hosted at bonsai.io, is a fully managed Elasticsearch and OpenSearch hosting platform built for developers and engineering teams. It is developed by One More Cloud, a small, bootstrapped, self-funded software company based in Austin, Texas, founded around 2009, with the Bonsai search product itself launching in 2012 as one of the first hosted Elasticsearch-as-a-service offerings on the market. In 2021 Bonsai became one of the first providers to offer managed OpenSearch alongside Elasticsearch, following the Elasticsearch and OpenSearch licensing split. It is critical to note that this bonsai.io product has no relationship whatsoever to Hello Bonsai, the freelancer business-management platform covered elsewhere in this directory at hellobonsai.com; the two companies were founded independently, serve entirely different markets, and only share a similar brand name. Bonsai.io reports managing more than 20,000 clusters and serving over one billion requests per day, and it is available as an add-on on platforms like Heroku in addition to its own direct signup. The company's pricing is structured across three broad tiers: a Standard tier ranging roughly from 25 to 400 dollars per month with named sub-plans such as Staging, Fir, Elm, Cork, Teak, and Oak, offering AI-ready vector search, 24 by 7 monitoring, and email support; a Business tier ranging roughly from 600 to 2,500 dollars per month adding a 99.99 percent uptime SLA, dedicated infrastructure, multi-availability-zone hosting, off-site backups, and a one-hour response-time SLA; and an Enterprise tier starting around 5,500 dollars per month that adds expert advisory support, zero-downtime upgrades, 24 by 7 emergency contact, bring-your-own-cloud deployment by default, and compliance features like FIPS-140-2 support. There is also a free Sandbox tier intended for experimentation and small development or research workloads. All plans include encryption, hourly backups, and GDPR and CCPA compliance, while Business and Enterprise plans add SOC 2 and HIPAA business-associate-agreement support. Bonsai.io is positioned as a low-overhead way for teams to run production search infrastructure without operating Elasticsearch or OpenSearch clusters themselves.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '6a378f3f-8fa1-4cc4-a151-94f0e9c1bddd';

