-- ── Bookmark OS ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Bookmark OS is a visual, browser-based bookmark manager and virtual desktop that lets users organize links, tabs, files, and notes using webpage-screenshot icons and a customizable drag-and-drop desktop.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free forever plan; one-time paid plan from $36$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE($q$Small, independent team$q$, company_size),
  headquarters = COALESCE($q$Seattle, Washington, US$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Bookmark OS Review: Visual Bookmark Manager Desktop$q$, seo_title),
  seo_meta_description = COALESCE($q$Bookmark OS is a visual bookmark manager and virtual desktop for organizing links, tabs, files, and notes. See features, pricing, and who it is for.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Bookmark OS, at bookmarkos.com, is a browser-based visual bookmark manager and virtual desktop created by web developer and entrepreneur David Lynam and headquartered in Seattle, Washington. Rather than presenting bookmarks as a plain text list, Bookmark OS renders them as visual icons generated from screenshots of the saved web page, and arranges them on a customizable, desktop-like workspace that supports familiar interactions such as drag and drop, drag-to-select, and right-click context menus. Beyond bookmarks, the product combines a tab manager that can save an entire browsing session into a folder, a notes feature for creating documents directly on the desktop, and file storage, positioning itself as a combined bookmark manager, tab manager, task manager, and notes tool in one interface. Additional features include AI-powered folder suggestions that recommend where a new bookmark should be saved, a duplicate bookmark finder to clean up existing collections, and weekly Dropbox backup syncing so a copy of the bookmark library is preserved outside the browser. The product ships with roughly ten selectable visual themes, appealing to a range of users including students, teachers, designers, and developers who want a more visual and spatial way of organizing links than a traditional folder tree. On pricing, Bookmark OS offers a free-forever plan, distinguishing it from purely subscription-based competitors, alongside a paid plan that uses a one-time, perpetual-license payment model starting at 36 dollars rather than a recurring monthly or annual subscription. This one-time pricing approach is relatively uncommon among modern SaaS bookmark tools, most of which charge ongoing subscriptions, and it is one of Bookmark OS's more distinctive positioning points. The tool is browser-based and works as an online workspace accessible from any device with a browser rather than as a native desktop or mobile application.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '4c469c6a-792c-487e-9146-9bc65b73f1e9';

