-- ── Bookworm ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Bookworm is a free, open-source ebook manager and reader built with GTK for elementary OS but usable on other Linux distributions, supporting EPUB, MOBI, PDF, and comic book formats.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Bookworm: Free Open-Source Ebook Reader for Linux$q$, seo_title),
  seo_meta_description = COALESCE($q$Bookworm is a free, open-source GTK ebook reader and library manager for Linux, supporting EPUB, MOBI, PDF, and comic formats.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Bookworm is a free, open-source ebook manager and reader created by developer Siddhartha Das, published under the GitHub username babluboy, and built with the Vala programming language along with GTK and WebKit for native integration on Linux desktops, particularly elementary OS. The source code is hosted at github.com/babluboy/bookworm, with a project page at babluboy.github.io/bookworm, and the application is distributed through Flathub, Snap packages, and Debian and Ubuntu package repositories, in addition to a dedicated Launchpad PPA. Bookworm supports a wide range of ebook and document formats, including EPUB, MOBI, PRC, PDF, and FB2, as well as comic book archive formats CBR and CBZ, making it useful for both text-based ebooks and digital comics. Its library management features let users tag books, edit and search metadata, and switch between grid and list views of their collection, with the ability to edit metadata directly from either view. For reading itself, Bookworm offers three built-in visual profiles, light, sepia, and dark, to reduce eye strain in different lighting conditions, supports bookmarking multiple pages within a book, and includes a full-screen reading mode accessible via the F11 shortcut. As a fully open-source project distributed under a free license, Bookworm has no cost, subscription, or premium tier of any kind; all features are available to every user who installs it. The project is designed primarily for elementary OS, where its interface most closely matches the platform's native design language, though it is packaged and usable on many other Linux distributions through Flatpak, Snap, and native distribution packages. It does not offer native Windows or macOS builds, and unlike more feature-heavy ebook management tools such as Calibre, it deliberately stays focused on a simple, lightweight reading and organization experience rather than offering format conversion, device syncing, or an extensive plugin ecosystem.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'c1619246-54cb-4904-969c-d8ab480b59b5';

