-- ── Boomi ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Boomi is a leading enterprise integration-platform-as-a-service (iPaaS) that connects applications, data, and APIs across cloud and on-premises systems, now owned by private equity firms Francisco Partners and TPG after being spun off from Dell Technologies in 2021.$q$, short_description),
  pricing_model = COALESCE($q$custom$q$, pricing_model),
  starting_price = COALESCE(NULL, starting_price),
  founded_year = COALESCE(2000, founded_year),
  company_size = COALESCE($q$Approximately 2,800-2,900 employees$q$, company_size),
  headquarters = COALESCE($q$Conshohocken, Pennsylvania, US$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Boomi Review 2026: Enterprise iPaaS Integration Platform$q$, seo_title),
  seo_meta_description = COALESCE($q$Boomi is a leading iPaaS connecting apps, data, and APIs. Learn its ownership by Francisco Partners and TPG, features, pricing, and possible 2026 IPO plans.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Boomi is an enterprise integration-platform-as-a-service, commonly called iPaaS, that connects applications, data, and APIs across cloud and on-premises systems for large organizations. The company was founded in 2000 in Berwyn, Pennsylvania, by Rick Nucci and Brian Mozhdehi, and launched its core integration service in 2007. Dell Technologies acquired Boomi in November 2010 and operated it as Dell Boomi. In 2021, Dell sold Boomi to a private equity consortium made up of Francisco Partners and TPG Capital in a deal valued at approximately 4 billion dollars, at which point the company was restructured as an independent entity, Boomi LP, and dropped the Dell name to become simply Boomi. As of the current reporting period, Boomi remains owned by Francisco Partners and TPG Capital. Late-2025 reporting indicated the two private equity owners were evaluating a possible initial public offering in 2026 targeting a valuation in the range of 7 to 9 billion dollars, contingent in part on customer adoption of Boomi's newer AI-driven features, marketed as Boomi GPT, and continued margin expansion under CEO Steve Lucas, whose appointment has been widely read by industry observers as a signal of IPO preparation given his track record scaling and exiting enterprise software companies. Boomi is headquartered in Conshohocken, Pennsylvania, having relocated there from Chesterbrook, Pennsylvania, in early 2024, and employs roughly 2,800 to 2,900 people worldwide as of recent counts, with workforce growth of more than 25 percent between 2023 and 2025. The Boomi platform itself provides a low-code, cloud-native integration process designer connecting SaaS applications, on-premises systems, and cloud infrastructure, alongside API management for designing and securing APIs, master data management for unifying and governing data across systems, B2B and EDI management for trading partner integrations, data preparation tooling, and generative AI-assisted integration building through Boomi GPT. Boomi sells to enterprise customers through custom, quote-based contracts rather than published self-serve pricing, with cost typically depending on connector usage, data volume, and the specific mix of integration, API management, and MDM products a customer adopts.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '5d45fb22-c16b-4b91-8bcb-5b311cde202a';

