-- ── boomurl ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$boomurl is a free static site hosting service that turns an uploaded HTML file or folder into a live public URL in about 20 seconds, built especially for publishing AI-generated pages, demos, resumes, and prototypes.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free; ad-removal add-on from $2/month per site$q$, starting_price),
  founded_year = COALESCE(2026, founded_year),
  company_size = COALESCE($q$Small, independent team$q$, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$boomurl Review: Instant Free Static Site Hosting$q$, seo_title),
  seo_meta_description = COALESCE($q$boomurl turns an HTML file or folder into a live URL in seconds. Free static hosting for AI-generated pages, demos, resumes, and prototypes.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$boomurl, at boomurl.com, is a free static site hosting service created by founder Doron Grinstein and launched in June 2026. Its core function is extremely simple: a user drags in an HTML file, or a folder containing an index.html file, along with any related assets such as Markdown files, PDFs, or plain text documents, picks a site name, verifies ownership via email with no password required, and receives a live public URL in about 20 seconds, with no build process, server configuration, or account setup required. boomurl positions itself explicitly around the rise of AI-generated web content, marketing itself as a fast way to publish pages produced by tools such as ChatGPT, Claude, Gemini, Cursor, and Replit, as well as more traditional use cases like sharing a resume, a quick demo, a prototype, or an event page. Beyond the core drag-and-drop web interface, boomurl offers developer-facing integrations including API access, a command-line interface tool, support for the Model Context Protocol so AI agents can publish sites programmatically, and an OpenAPI specification for automated integrations. Users can also point their own custom domain at a boomurl-hosted site rather than using boomurl's free subdomain. The free tier allows sites up to 50 megabytes and 500 files, with a small hosted-by-boomurl banner displayed at the bottom of published pages; removing that banner costs 2 dollars per month per site through a prepaid credit system. Because boomurl only hosts static content, it is not designed for dynamic web applications requiring server-side logic, databases, or user authentication; its scope is deliberately limited to fast, no-friction publishing of already-built static files. As a service that launched in mid-2026, boomurl is a very new entrant in the static hosting space, distinguishing itself from more established competitors like Netlify, Vercel, or GitHub Pages primarily through its emphasis on speed, zero-configuration publishing, and first-class support for AI agents and AI-generated content as a direct publishing target.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '117ca2a8-f16a-4fc1-bccc-aadb5800f356';

