INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('117ca2a8-f16a-4fc1-bccc-aadb5800f356', $q$Smaller ecosystem and community than established static hosts like Netlify or GitHub Pages$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('117ca2a8-f16a-4fc1-bccc-aadb5800f356', $q$What is boomurl?$q$, $q$boomurl is a free static site hosting service that turns an uploaded HTML file or folder into a live public URL in about 20 seconds.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('117ca2a8-f16a-4fc1-bccc-aadb5800f356', $q$Is boomurl free?$q$, $q$Yes, boomurl is free to use within its file-size and file-count limits, with an optional 2 dollar per month per site charge to remove the hosted-by-boomurl banner.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('117ca2a8-f16a-4fc1-bccc-aadb5800f356', $q$What can I upload to boomurl?$q$, $q$boomurl accepts HTML files, Markdown files, PDFs, plain text documents, and full folders containing an index.html file.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('117ca2a8-f16a-4fc1-bccc-aadb5800f356', $q$How fast does a boomurl site go live?$q$, $q$Sites typically go live in about 20 seconds after upload and email verification.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('117ca2a8-f16a-4fc1-bccc-aadb5800f356', $q$Can AI agents publish directly to boomurl?$q$, $q$Yes, boomurl supports the Model Context Protocol along with API and CLI access so AI agents can publish sites programmatically.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('117ca2a8-f16a-4fc1-bccc-aadb5800f356', $q$Does boomurl support custom domains?$q$, $q$Yes, users can point their own custom domain at a site hosted on boomurl.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('117ca2a8-f16a-4fc1-bccc-aadb5800f356', $q$What are boomurl's file limits?$q$, $q$Free sites on boomurl support up to 50 megabytes of storage and 500 files.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('117ca2a8-f16a-4fc1-bccc-aadb5800f356', $q$Who created boomurl?$q$, $q$boomurl was created by founder Doron Grinstein and launched in June 2026.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('117ca2a8-f16a-4fc1-bccc-aadb5800f356', $q$Publishing AI-generated prototypes$q$, $q$Developers and AI agents use boomurl to instantly publish static pages generated by tools like ChatGPT, Claude, or Cursor.$q$, $q$Developers and AI power users$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('117ca2a8-f16a-4fc1-bccc-aadb5800f356', $q$Hosting a resume or portfolio page$q$, $q$Job seekers and freelancers use boomurl to quickly publish a resume or simple portfolio page without setting up hosting infrastructure.$q$, $q$Individuals and freelancers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('117ca2a8-f16a-4fc1-bccc-aadb5800f356', $q$Sharing one-off landing or event pages$q$, $q$Marketers and founders use boomurl to publish quick landing pages or event pages without involving a full web development workflow.$q$, $q$Marketers and founders$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('117ca2a8-f16a-4fc1-bccc-aadb5800f356', $q$Free$q$, $q$$0$q$, $q$free$q$, NULL, $q$["Static site hosting up to 50MB and 500 files","Live URL in about 20 seconds","Hosted-by-boomurl banner included"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('117ca2a8-f16a-4fc1-bccc-aadb5800f356', $q$Ad-Free$q$, $q$$2/month per site$q$, $q$monthly (prepaid credits)$q$, NULL, $q$["Removes the hosted-by-boomurl banner","Same file-size and file-count limits as Free","Custom domain support"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('117ca2a8-f16a-4fc1-bccc-aadb5800f356', $q$overview$q$, $q$What Is boomurl$q$, 2, ARRAY[$q$boomurl, at boomurl.com, is a free static site hosting service that turns an uploaded HTML file or folder into a live public URL in about 20 seconds. It was created by founder Doron Grinstein and launched in June 2026.$q$, $q$The product is built around simplicity: users drag in a file or folder, pick a site name, verify their email with no password required, and get a live link almost immediately, with no build step, server setup, or account onboarding involved.$q$, $q$boomurl markets itself heavily around the rise of AI-generated content, positioning itself as a natural publishing destination for pages produced by tools like ChatGPT, Claude, Gemini, Cursor, and Replit, in addition to more conventional use cases such as resumes, demos, prototypes, and event pages.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('117ca2a8-f16a-4fc1-bccc-aadb5800f356', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core publishing supports HTML pages, Markdown files, PDFs, and plain text documents, along with full folder uploads, and each free site is capped at 50 megabytes and 500 files. Security is handled through email verification and IP logging rather than requiring a password or full account setup.$q$, $q$For developers and AI agents, boomurl offers API access, a command-line interface, an OpenAPI specification, and support for the Model Context Protocol, allowing AI tools to publish sites programmatically. Users can also connect a custom domain to a boomurl-hosted site instead of using the default subdomain.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('117ca2a8-f16a-4fc1-bccc-aadb5800f356', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$boomurl is free to use for publishing static sites within its file-size and file-count limits, with a small hosted-by-boomurl banner displayed at the bottom of pages on the free tier.$q$, $q$Removing that banner costs 2 dollars per month per site, purchased through a prepaid credit system, making boomurl one of the lowest-cost static hosting options available for users who want an ad-free published page.$q$]::text[], 2);
